import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule, NgIf, NgFor } from '@angular/common';

@Component({
  selector: 'app-ats-pipeline',
  standalone: true,
  imports: [CommonModule, NgIf, NgFor],
  templateUrl: './ats-pipeline.component.html',
  styleUrls: ['./ats-pipeline.component.css']
})
export class AtsPipelineComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // Contient l'ensemble des candidatures extraites de l'API
  applicationsList: any[] = []; 
  
  // Stocke la candidature active pour la fenêtre de consultation
  selectedApplication: any = null; 

  ngOnInit() {
    this.fetchApplications();
  }

  fetchApplications() {
    const targetUrl = 'http://localhost:3000/api/recruiter/ats/applications';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : '' 
      }
    })
    .then(res => {
      if (!res.ok) throw new Error("Impossible de charger le pipeline ATS.");
      return res.json();
    })
    .then(data => {
      // 🚀 CORRECTION : Extraction du tableau depuis la clé "applications" renvoyée par le backend
      this.applicationsList = data && Array.isArray(data.applications) ? data.applications : [];
      this.cdr.detectChanges();
      console.log("✅ Candidatures chargées avec succès :", this.applicationsList);
    })
    .catch(err => {
      console.error("❌ Erreur lors de la récupération du pipeline ATS :", err);
    });
  }

  /**
   * Trie les profils par colonne Kanban selon leur statut
   */
  getCandidatesByStatus(statusName: string): any[] {
    return this.applicationsList.filter(app => {
      if (!app.status) {
        return statusName === 'Nouveau'; // Par défaut
      }
      
      const currentStatus = app.status.toLowerCase().trim();
      
      // Correspondance avec les statuts de votre base de données
      if (statusName === 'Nouveau') {
        return currentStatus.includes('nouv') || currentStatus.includes('att') || currentStatus === 'pending';
      }
      if (statusName === 'Entretien') {
        return currentStatus.includes('entre') || currentStatus.includes('tech');
      }
      if (statusName === 'Proposition') {
        return currentStatus.includes('prop') || currentStatus.includes('offr') || currentStatus.includes('acc');
      }
      
      return false;
    });
  }

  onSelectApplication(app: any) {
    this.selectedApplication = app;
    this.cdr.detectChanges();
  }

  onCloseDetails() {
    this.selectedApplication = null;
    this.cdr.detectChanges();
  }
}
<div class="ats-container">
  <div class="ats-card">
    <div class="card-header">
      <h3><i class="bi bi-people-fill"></i> Suivi des Candidats (Pipeline ATS)</h3>
      <p>Suivez pas à pas la progression de vos candidats dans le tunnel de recrutement.</p>
    </div>

    <!-- Les colonnes Kanban du logiciel de recrutement -->
    <div class="pipeline-grid">
      
      <!-- 1. Colonne : Nouveaux CV -->
      <div class="pipeline-column">
        <div class="column-header">
          Nouveaux CV 
          <span class="count">{{ getCandidatesByStatus('Nouveau').length }}</span>
        </div>
        
        <div *ngFor="let app of getCandidatesByStatus('Nouveau')" 
             (click)="onSelectApplication(app)"
             class="candidate-item">
          <h5>{{ app.name }}</h5>
          <p>{{ app.job_title }}</p>
          <span class="location"><i class="bi bi-geo-alt"></i> {{ app.address || 'Tunis' }}</span>
        </div>

        <!-- Espace visuel si la colonne est vide -->
        <div *ngIf="getCandidatesByStatus('Nouveau').length === 0" class="empty-placeholder">
          <i class="bi bi-folder-plus"></i>
          <p>Aucun nouveau CV</p>
        </div>
      </div>

      <!-- 2. Colonne : Entretien Tech -->
      <div class="pipeline-column">
        <div class="column-header">
          Entretien Tech 
          <span class="count">{{ getCandidatesByStatus('Entretien').length }}</span>
        </div>
        
        <div *ngFor="let app of getCandidatesByStatus('Entretien')" 
             (click)="onSelectApplication(app)"
             class="candidate-item border-orange">
          <h5>{{ app.name }}</h5>
          <p>{{ app.job_title }}</p>
          <span class="location"><i class="bi bi-geo-alt"></i> {{ app.address || 'Tunis' }}</span>
        </div>

        <!-- Espace visuel si la colonne est vide -->
        <div *ngIf="getCandidatesByStatus('Entretien').length === 0" class="empty-placeholder">
          <i class="bi bi-calendar-event"></i>
          <p>Aucun entretien planifié</p>
        </div>
      </div>

      <!-- 3. Colonne : Proposition -->
      <div class="pipeline-column">
        <div class="column-header">
          Proposition 
          <span class="count">{{ getCandidatesByStatus('Proposition').length }}</span>
        </div>
        
        <div *ngFor="let app of getCandidatesByStatus('Proposition')" 
             (click)="onSelectApplication(app)"
             class="candidate-item border-green">
          <h5>{{ app.name }}</h5>
          <p>{{ app.job_title }}</p>
          <span class="location"><i class="bi bi-geo-alt"></i> {{ app.address || 'Tunis' }}</span>
        </div>

        <!-- Espace visuel si la colonne est vide -->
        <div *ngIf="getCandidatesByStatus('Proposition').length === 0" class="empty-placeholder">
          <i class="bi bi-check-circle"></i>
          <p>Aucune proposition émise</p>
        </div>
      </div>

    </div>
  </div>
</div>

<!-- ========================================================================== -->
<!-- 🚀 FENÊTRE MODALE DE CONSULTATION DE LA CANDIDATURE                        -->
<!-- ========================================================================== -->
<div *ngIf="selectedApplication" class="modal-overlay" (click)="onCloseDetails()">
  <div class="modal-content" (click)="$event.stopPropagation()">
    
    <!-- En-tête -->
    <div class="modal-header">
      <h3><i class="bi bi-file-earmark-person"></i> Candidature de {{ selectedApplication.name }}</h3>
      <button class="close-btn" (click)="onCloseDetails()">&times;</button>
    </div>

    <!-- Corps des détails -->
    <div class="modal-body">
      <div class="info-row">
        <span class="info-label">Poste ciblé :</span> 
        <strong class="info-value text-slate">{{ selectedApplication.job_title }}</strong>
      </div>
      <div class="info-row">
        <span class="info-label">Adresse e-mail :</span> 
        <span class="info-value">{{ selectedApplication.email }}</span>
      </div>
      <div class="info-row">
        <span class="info-label">Numéro de téléphone :</span> 
        <span class="info-value">{{ selectedApplication.phone || 'Non renseigné' }}</span>
      </div>
      <div class="info-row">
        <span class="info-label">Ville / Région :</span> 
        <span class="info-value"><i class="bi bi-geo-alt"></i> {{ selectedApplication.address || 'Non spécifiée' }}</span>
      </div>
      
      <div class="summary-box">
        <span class="summary-title">Résumé du profil & compétences :</span>
        <p class="summary-text">{{ selectedApplication.cv_summary || 'Aucun résumé disponible pour ce candidat.' }}</p>
      </div>
    </div>

    <!-- Pied de page -->
    <div class="modal-footer">
      <button class="btn-secondary" (click)="onCloseDetails()">Fermer</button>
    </div>

  </div>
</div>
